cd /tmp/sv-82afb2fdbf97428f82823b45b71ea2f2/simple-solution && dotnet list package --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)
def get_pkgs(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result
b, a = get_pkgs(baseline), get_pkgs(after)
if b == a:
    print('All packages resolve identically - conversion is version-neutral.')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv, av = b.get(k, 'MISSING'), a.get(k, 'MISSING')
        if bv != av: print(f'CHANGED: {k} {bv} -> {av}')
